// CreateSubscription is the resolver for the createSubscription field.
func (r *mutationResolver) CreateSubscription(ctx context.Context, input model.CreateSubscriptionInput) (*model.ServiceSubscription, error) {
	claims := auth.GetUserFromContext(ctx)
	if claims == nil {
		return nil, fmt.Errorf("not authenticated")
	}

	// Resolve address.
	var addressID pgtype.UUID
	if input.AddressID != nil && *input.AddressID != "" {
		addressID = stringToUUID(*input.AddressID)
	} else if input.Address != nil {
		addr, err := r.Queries.CreateAddress(ctx, db.CreateAddressParams{
			UserID:        stringToUUID(claims.UserID),
			Label:         stringToText(input.Address.Label),
			StreetAddress: input.Address.StreetAddress,
			City:          input.Address.City,
			County:        input.Address.County,
			PostalCode:    stringToText(input.Address.PostalCode),
			Floor:         stringToText(input.Address.Floor),
			Apartment:     stringToText(input.Address.Apartment),
			EntryCode:     stringToText(input.Address.EntryCode),
			Latitude:      float64PtrToFloat8(input.Address.Latitude),
			Longitude:     float64PtrToFloat8(input.Address.Longitude),
			Notes:         stringToText(input.Address.Notes),
			IsDefault:     pgtype.Bool{Bool: false, Valid: true},
		})
		if err != nil {
			return nil, fmt.Errorf("failed to create address: %w", err)
		}
		addressID = addr.ID
	} else {
		return nil, fmt.Errorf("addressId or address is required")
	}

	// Resolve worker and company.
	workerUUID := stringToUUID(input.PreferredWorkerID)
	worker, err := r.Queries.GetWorkerByID(ctx, workerUUID)
	if err != nil {
		return nil, fmt.Errorf("worker not found: %w", err)
	}

	// Calculate pricing (hourly rate, estimated total, etc.)
	dbServiceType := gqlServiceTypeToDb(input.ServiceType)
	service, err := r.Queries.GetServiceByType(ctx, dbServiceType)
	if err != nil {
		return nil, fmt.Errorf("service not found: %w", err)
	}

	hourlyRate := numericToFloat(service.BasePricePerHour)

	// Resolve commission rate: per-company override -> platform default.
	commissionPct := 25.0 // fallback
	if company, cErr := r.Queries.GetCompanyByID(ctx, worker.CompanyID); cErr == nil && company.CommissionOverridePct.Valid {
		commissionPct = numericToFloat(company.CommissionOverridePct)
	} else if setting, sErr := r.Queries.GetPlatformSetting(ctx, "platform_commission_pct"); sErr == nil {
		if v := numericFromString(setting.Value); v > 0 {
			commissionPct = v
		}
	}

	// Calculate estimated hours and total.
	estimatedHours := calculateEstimatedHours(input.NumRooms, input.NumBathrooms, input.AreaSqm)
	estimatedTotal := hourlyRate * estimatedHours

	// Add extras cost.
	if input.Extras != nil {
		for _, extra := range input.Extras {
			extraDef, extraErr := r.Queries.GetExtraByID(ctx, stringToUUID(extra.ExtraID))
			if extraErr == nil {
				estimatedTotal += numericToFloat(extraDef.Price) * float64(extra.Quantity)
			}
		}
	}

	// Parse preferred time.
	preferredTime, err := time.Parse("15:04", input.PreferredTime)
	if err != nil {
		return nil, fmt.Errorf("invalid preferred time format (expected HH:MM): %w", err)
	}

	// Get payment method's Stripe ID.
	pmUUID := stringToUUID(input.PaymentMethodID)
	pm, err := r.Queries.GetPaymentMethodByID(ctx, pmUUID)
	if err != nil {
		return nil, fmt.Errorf("payment method not found: %w", err)
	}
	if !pm.StripePaymentMethodID.Valid || pm.StripePaymentMethodID.String == "" {
		return nil, fmt.Errorf("payment method has no Stripe ID")
	}

	// Build extras input.
	var extras []subSvc.ExtraInput
	if input.Extras != nil {
		for _, e := range input.Extras {
			extras = append(extras, subSvc.ExtraInput{
				ExtraID:  stringToUUID(e.ExtraID),
				Quantity: e.Quantity,
			})
		}
	}

	// Get user info.
	user, err := r.Queries.GetUserByID(ctx, stringToUUID(claims.UserID))
	if err != nil {
		return nil, fmt.Errorf("failed to get user: %w", err)
	}

	sub, err := r.SubscriptionService.CreateSubscription(ctx, subSvc.CreateSubscriptionInput{
		ClientUserID:    stringToUUID(claims.UserID),
		ClientEmail:     user.Email,
		ClientName:      user.FullName,
		WorkerID:        workerUUID,
		CompanyID:       worker.CompanyID,
		AddressID:       addressID,
		RecurrenceType:  gqlRecurrenceTypeToDb(input.RecurrenceType),
		DayOfWeek:       input.DayOfWeek,
		PreferredTime:   preferredTime,
		ServiceType:     dbServiceType,
		PropertyType:    input.PropertyType,
		NumRooms:        input.NumRooms,
		NumBathrooms:    input.NumBathrooms,
		AreaSqm:         input.AreaSqm,
		HasPets:         input.HasPets,
		SpecialInstr:    input.SpecialInstructions,
		HourlyRate:      hourlyRate,
		EstimatedHours:  estimatedHours,
		EstimatedTotal:  estimatedTotal,
		PaymentMethodID: pm.StripePaymentMethodID.String,
		CommissionPct:   commissionPct,
		Extras:          extras,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to create subscription: %w", err)
	}

	// Notify client that subscription is confirmed (non-blocking).
	r.dispatchSubscriptionConfirmed(sub)

	return r.fullSubscription(ctx, sub)
}

